import requests

def test_post_v1_batches_validation_errors():
    base_url = "http://localhost:8000"
    url = f"{base_url}/v1/batches"
    timeout = 30

    test_data = [
        ({}, 422),
        ({"source_url": "http://x.com", "count": "4"}, 422),  # count < 5
        ({"source_url": "http://x.com", "count": "16"}, 422), # count > 15
        ({"count": "5"}, 422)  # no source_url
    ]

    headers = {
        "Accept": "application/json"
    }

    for data, expected_status in test_data:
        try:
            response = requests.post(url, data=data, headers=headers, timeout=timeout)
        except requests.RequestException as e:
            assert False, f"Request failed with exception: {e}"

        assert response.status_code == expected_status, (
            f"Expected status {expected_status} but got {response.status_code} for data: {data}"
        )

test_post_v1_batches_validation_errors()

import requests

def test_get_v1_batches_uuid_validation_and_404():
    base_url = "http://localhost:8000"
    timeout = 30

    # 1. GET /v1/batches/not-a-uuid → expect 422 (invalid UUID)
    url_invalid_uuid = f"{base_url}/v1/batches/not-a-uuid"
    try:
        response_invalid_uuid = requests.get(url_invalid_uuid, timeout=timeout)
    except requests.RequestException as e:
        assert False, f"Request to {url_invalid_uuid} failed: {e}"
    else:
        assert response_invalid_uuid.status_code == 422, (
            f"Expected status 422 for invalid UUID, got {response_invalid_uuid.status_code}, "
            f"response: {response_invalid_uuid.text}"
        )

    # 2. GET /v1/batches/00000000-0000-0000-0000-000000000000 → expect 404 (valid UUID but not found)
    valid_but_not_found_uuid = "00000000-0000-0000-0000-000000000000"
    url_not_found = f"{base_url}/v1/batches/{valid_but_not_found_uuid}"
    try:
        response_not_found = requests.get(url_not_found, timeout=timeout)
    except requests.RequestException as e:
        assert False, f"Request to {url_not_found} failed: {e}"
    else:
        assert response_not_found.status_code == 404, (
            f"Expected status 404 for valid but non-existent UUID, got {response_not_found.status_code}, "
            f"response: {response_not_found.text}"
        )

test_get_v1_batches_uuid_validation_and_404()

import requests

BASE_URL = "http://localhost:8000"
TIMEOUT = 30

def test_post_v1_agents_webhooks_elevenlabs_signature():
    url = f"{BASE_URL}/v1/agents/webhooks/elevenlabs"
    json_body = {"test": "data"}

    # Case 1: No signature header → 400 with expected detail
    try:
        response = requests.post(url, json=json_body, timeout=TIMEOUT)
    except Exception as e:
        assert False, f"Request to {url} failed: {e}"
    assert response.status_code == 400, f"Expected 400, got {response.status_code}"
    try:
        resp_json = response.json()
    except Exception:
        assert False, "Response is not valid JSON"
    detail = resp_json.get("detail") or resp_json.get("message") or ""
    assert "Missing ElevenLabs webhook signature header." in detail, f"Unexpected detail message: {detail}"

    # Case 2: Fake signature header with JSON body → 400
    headers = {
        "elevenlabs-signature": "fake"
    }
    try:
        response = requests.post(url, json=json_body, headers=headers, timeout=TIMEOUT)
    except Exception as e:
        assert False, f"Request to {url} failed: {e}"
    assert response.status_code == 400, f"Expected 400, got {response.status_code}"

test_post_v1_agents_webhooks_elevenlabs_signature()
